package pe.edu.utp.tmo.security;
import jakarta.servlet.*; import jakarta.servlet.http.*; import java.io.IOException; import org.apache.commons.lang3.StringUtils; import org.springframework.security.authentication.UsernamePasswordAuthenticationToken; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.security.web.authentication.WebAuthenticationDetailsSource; import org.springframework.stereotype.Component; import org.springframework.web.filter.OncePerRequestFilter;
@Component public class JwtAuthenticationFilter extends OncePerRequestFilter {
 private final JwtService jwt; private final CustomUserDetailsService users; public JwtAuthenticationFilter(JwtService jwt,CustomUserDetailsService users){this.jwt=jwt;this.users=users;}
 protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain) throws ServletException,IOException{String h=req.getHeader("Authorization"); if(StringUtils.isBlank(h)||!h.startsWith("Bearer ")){chain.doFilter(req,res);return;} try{String token=h.substring(7); String correo=jwt.correo(token); if(SecurityContextHolder.getContext().getAuthentication()==null){UserPrincipal p=(UserPrincipal)users.loadUserByUsername(correo); if(jwt.valido(token,p)){UsernamePasswordAuthenticationToken a=new UsernamePasswordAuthenticationToken(p,null,p.getAuthorities()); a.setDetails(new WebAuthenticationDetailsSource().buildDetails(req)); SecurityContextHolder.getContext().setAuthentication(a);}}}catch(RuntimeException ex){SecurityContextHolder.clearContext();} chain.doFilter(req,res);}
}
